// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Local actions and streams — manually managed without external hooks
  let taskUpdate: (payload: ActionTaskUpdatePayload) => void = () => {};
  let taskChanged: { latest: StreamTaskChanged | null; all: StreamTaskChanged[] } = { latest: null, all: [] };

  // Local state for task management
  const [tasks, setTasks] = useState(props.tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Listen for real-time task updates via ggui:agent-data events
  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail?.type === 'taskChanged' && customEvent.detail?.payload) {
        const updatedTask = customEvent.detail.payload.task;
        const action = customEvent.detail.payload.action;

        if (updatedTask) {
          setTasks((prevTasks) => {
            if (action === 'create') {
              return [...prevTasks, updatedTask];
            } else if (action === 'delete') {
              return prevTasks.filter((t) => t.id !== updatedTask.id);
            } else if (action === 'move' || action === 'edit') {
              return prevTasks.map((t) => (t.id === updatedTask.id ? updatedTask : t));
            }
            return prevTasks;
          });
        }
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Computed: group tasks by column
  const tasksByColumn = useCallback(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns.forEach((col) => {
      grouped[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  // Computed: summary stats
  const stats = useCallback(() => {
    const total = tasks.length;
    const completed = tasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [tasks]);

  // Handler: move task to column
  // Handler: move task to column
  const handleMoveTask = useCallback((taskId: string, toColumn: string) => {
    setTasks((prevTasks) =>
      prevTasks.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
  }, []);

  // Handler: edit task title
  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    setTasks((prevTasks) =>
      prevTasks.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
    );
    setEditingTaskId(null);
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
  }, [tasks]);

  // Handler: add new task
  const handleAddTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTaskId = `task-${Date.now()}`;
    const newTask = {
      id: newTaskId,
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: undefined,
      dueDate: undefined,
    };
    setTasks((prevTasks) => [...prevTasks, newTask]);
    taskUpdate({ action: 'create', taskId: newTaskId, data: { column: columnId } });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingToColumn(null);
  }, [newTaskTitle, newTaskPriority]);

  return {
    tasks,
    setTasks,
    editingTaskId,
    setEditingTaskId,
    addingToColumn,
    setAddingToColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    tasksByColumn,
    stats,
    handleMoveTask,
    handleEditTask,
    handleAddTask,
  };
}
export default function Component(props: Props) {
  const state = useComponent(props);
  const grouped = state.tasksByColumn();
  const { total, completed } = state.stats();

  // Get priority badge color
  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
      default:
        return 'success';
    }
  };

  return (
    <Stack gap={24}>
      {/* Summary bar */}
      <Box background="var(--ggui-color-primary-50, #f0f9ff)" padding={16} borderRadius={8}>
        <Row gap={32} align="center">
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Total Tasks</Text>
            <Text size="2xl" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">{total}</Text>
          </Stack>
          <Divider orientation="vertical" margin={0} />
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Completed</Text>
            <Text size="2xl" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">{completed}</Text>
          </Stack>
          <Spacer size="flex" />
          <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">{total > 0 ? Math.round((completed / total) * 100) : 0}% complete</Text>
        </Row>
      </Box>

      {/* Kanban board */}
      <Row gap={16} align="start" wrap>
        {props.columns.map((column) => {
          const columnTasks = grouped[column.id || ''] || [];

          return (
            <Stack key={column.id} gap={12} style={{ flex: '0 1 350px', minWidth: '300px' }}>
              {/* Column header */}
              <Row gap={8} align="center" justify="between">
                <Heading level={4}>{column.name}</Heading>
                <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
              </Row>

              {/* Task cards */}
              <Stack gap={12}>
                {columnTasks.map((task) => (
                  <Card key={task.id} shadow="sm" padding={12} radius="md">
                    <Stack gap={8}>
                      {/* Task title (editable) */}
                      {state.editingTaskId === task.id ? (
                        <Input
                          label="Task title"
                          value={task.title || ''}
                          onChange={(value) => state.setTasks((prev) => prev.map((t) => t.id === task.id ? { ...t, title: value } : t))}
                          size="sm"
                        />
                      ) : (
                        <Text
                          as={Clickable}
                          onClick={() => state.setEditingTaskId(task.id || null)}
                           style={{ cursor: 'pointer', padding: 'var(--ggui-spacing-1, 4px)', borderRadius: 'var(--ggui-shape-radius-sm, 4px)' }}
                          weight="semibold"
                        >
                          {task.title || 'Untitled'}
                        </Text>
                      )}

                      {/* Priority badge */}
                      {task.priority && (
                        <Badge variant={getPriorityVariant(task.priority)} size="sm" pill>
                          {task.priority}
                        </Badge>
                      )}

                      {/* Assignee avatar */}
                      {task.assignee && (
                        <Avatar name={task.assignee} size="sm" />
                      )}

                      {/* Due date */}
                      {task.dueDate && (
                        <Row gap={4} align="center">
                          <Icon name="calendar" size={14} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.dueDate}</Text>
                        </Row>
                      )}

                      {/* Move and edit controls */}
                      <Row gap={6} justify="between">
                        <Button
                          size="xs"
                          variant="ghost"
                          onClick={() => state.setEditingTaskId(state.editingTaskId === task.id ? null : task.id || null)}
                        >
                          <Icon name={state.editingTaskId === task.id ? 'check' : 'edit'} size={14} />
                        </Button>
                        {state.editingTaskId === task.id && (
                          <Button
                            size="xs"
                            variant="ghost"
                            onClick={() => {
                              state.handleEditTask(task.id || '', task.title || '');
                            }}
                          >
                            Save
                          </Button>
                        )}
                        <Dropdown
                          trigger={<Button size="xs" variant="outline"><Icon name="arrow-right" size={14} /></Button>}
                          options={props.columns
                            .filter((col) => col.id !== column.id)
                            .map((col) => ({
                              value: col.id || '',
                              label: `Move to ${col.name}`,
                            }))}
                          value=""
                          onChange={(toColumn) => state.handleMoveTask(task.id || '', toColumn)}
                          placement="bottom-end"
                        />
                      </Row>
                    </Stack>
                  </Card>
                ))}
              </Stack>

              {/* Add task form */}
              {state.addingToColumn === column.id ? (
                <Card shadow="sm" padding={12} radius="md" border={false}>
                  <Stack gap={8}>
                    <Input
                      label="Task title"
                      placeholder="Enter task title..."
                      value={state.newTaskTitle}
                      onChange={state.setNewTaskTitle}
                      size="sm"
                    />
                    <Select
                      label="Priority"
                      value={state.newTaskPriority}
                      onChange={(val) => state.setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                      size="sm"
                    />
                    <Row gap={6}>
                      <Button
                        size="xs"
                        variant="primary"
                        onClick={() => state.handleAddTask(column.id || '')}
                      >
                        Add
                      </Button>
                      <Button
                        size="xs"
                        variant="ghost"
                        onClick={() => {
                          state.setAddingToColumn(null);
                          state.setNewTaskTitle('');
                          state.setNewTaskPriority('medium');
                        }}
                      >
                        Cancel
                      </Button>
                    </Row>
                  </Stack>
                </Card>
              ) : (
                <Button
                  size="sm"
                  variant="ghost"
                  fullWidth
                  onClick={() => state.setAddingToColumn(column.id || '')}
                  leftIcon={<Icon name="plus" size={16} />}
                >
                  Add Task
                </Button>
              )}
            </Stack>
          );
        })}
      </Row>
    </Stack>
  );
}
